import os
import sys
import json
import pytest
from pathlib import Path

# Add project root to path
project_root = Path(__file__).resolve().parent.parent.parent
sys.path.insert(0, str(project_root / 'code'))

from src.utils.config import get_path

def load_alignment_report():
    """Load the alignment report generated by T025."""
    report_path = get_path('results', 'alignment_report.json')
    if not Path(report_path).exists():
        # If file doesn't exist, return None to indicate test setup failure
        return None
    with open(report_path, 'r') as f:
        return json.load(f)

@pytest.fixture
def report():
    return load_alignment_report()

def test_alignment_file_exists(report):
    """Test that the alignment report file exists."""
    assert report is not None, "alignment_report.json does not exist. Run T025 first."

def test_alignment_schema_has_required_keys(report):
    """Test that the report contains all required keys."""
    required_keys = ['task_id', 'status', 'timestamp', 'calibration_valid', 'alignment_metrics', 'pass_threshold', 'recommendation']
    for key in required_keys:
        assert key in report, f"Missing required key: {key}"

def test_alignment_metrics_structure(report):
    """Test that alignment_metrics contains the correct sub-keys."""
    metrics = report['alignment_metrics']
    required_metrics = ['iou_depth_grid', 'iou_rgb_grid', 'overall_iou', 'threshold', 'passed']
    for key in required_metrics:
        assert key in metrics, f"Missing metric key: {key}"

def test_iou_values_range(report):
    """Test that IoU values are between 0 and 1."""
    metrics = report['alignment_metrics']
    assert 0.0 <= metrics['iou_depth_grid'] <= 1.0, "iou_depth_grid out of range"
    assert 0.0 <= metrics['iou_rgb_grid'] <= 1.0, "iou_rgb_grid out of range"
    assert 0.0 <= metrics['overall_iou'] <= 1.0, "overall_iou out of range"

def test_threshold_value(report):
    """Test that the threshold is set to 0.95."""
    assert report['alignment_metrics']['threshold'] == 0.95

def test_status_is_completed(report):
    """Test that the status is 'completed'."""
    assert report['status'] == 'completed'

def test_recommendation_logic(report):
    """Test that recommendation matches the passed flag."""
    metrics = report['alignment_metrics']
    rec = report['recommendation']
    if metrics['passed']:
        assert "Pass" in rec, "Recommendation should indicate Pass when metrics passed"
    else:
        assert "FAIL" in rec, "Recommendation should indicate FAIL when metrics failed"